--将超过11个字符的字符串表示成8个字符的缩写形式，如:“123456789123”,表示成“12345678...”
function Utility.toAbbreviateString(str)
    --print(str)
    if string.len(str) >= 11 then
        str = string.sub(str, 1, 8).."..."
    end
    --print("省略")
    --print(str)
    return str
end

