function Utility.stringToTable(str)
    local result = {}

    for _, pair in pairs(StringUtil.split(str, "#")) do
        local kv = StringUtil.split(pair, ",")
        result[kv[1]] = tonumber(kv[2])
    end

    --print(string.format("Utility.stringToTable %s %s", str, inspect.inspect(result)))

    return result
end

local function showFloatNumber_inner(pEntity, damage, color, scaleCoe)
    if not pEntity then
        --LogUtil.log("Utility.showFloatNumber not pEntity")
        return
    end

    local entityRenderManager = EntityRenderManager.Instance()
    if not entityRenderManager then
        --LogUtil.log("Utility.showFloatNumber not entityRenderManager")
        return
    end

    local actor = entityRenderManager:getEntityActor(pEntity)
    if not actor then
        --LogUtil.log("Utility.showFloatNumber not actor")
        return
    end

    local pos = pEntity:getBottomPos()
    local scale = actor:GetTotalScale().y
    pos.y = pos.y + (pEntity:getHeight() * GameConfig.showFloatNumberPosCoe * scale)

    --随机位置
    --local offset = 1
    --pos.x = math.random(pos.x - offset, pos.x + offset)
    --pos.y = math.random(pos.y - offset, pos.y + offset)
    --pos.z = math.random(pos.z - offset, pos.z + offset)

    local pullDistance = 0
    WorldImageRender.Instance():addFloatNumber(Utility.toKMBString(tostring(damage), 2),
            pos, (1 + scale) * scaleCoe, color or 1, pullDistance)
end

function Utility.showFloatNumber(pEntity, pAttacker, damage, color)
    showFloatNumber_inner(pEntity, damage, color, GameConfig.showFloatNumberScaleCoeHurter)
    showFloatNumber_inner(pAttacker, damage, color, GameConfig.showFloatNumberScaleCoeAttacker)
end

function Utility.refreshPoleControlState(state)
    if Platform.isWindow() then
        return
    end

    local gui_menu = DynamicCastHelper.dynamicCastGuiMenu(RootGuiLayout.Instance():getLayout(7))
    if not gui_menu then
        return
    end

    local gui_gameSetting = DynamicCastHelper.dynamicCastGuiGameSetting(gui_menu:getRadioPanel(3))
    if not gui_gameSetting then
        return
    end

    gui_gameSetting:refreshPoleControlState(state)

    LogUtil.log(string.format("Utility.refreshPoleControlState %d", state))
end

function Utility.updateCameraDistance(bForce)
    local gui_mainControl = DynamicCastHelper.dynamicCastGuiMainControl(RootGuiLayout.Instance():getLayout(0))
    if gui_mainControl then
        LogUtil.log("gui_mainControl:updateCameraDistance " .. tostring(bForce))
        gui_mainControl:updateCameraDistance(bForce)
    end
end

return Utility